const express = require('express');
const session = require('express-session');
const crypto = require('crypto');
const rateLimit = require('express-rate-limit');
const helmet = require('helmet');

const app = express();

app.use(helmet());
app.use(express.json());
app.use(express.urlencoded({ extended: true }));

const sessionConfig = {
  secret: process.env.SESSION_SECRET || crypto.randomBytes(32).toString('hex'),
  resave: false,
  saveUninitialized: false,
  cookie: {
    secure: process.env.NODE_ENV === 'production',
    httpOnly: true,
    maxAge: 1800000,
    sameSite: 'strict'
  },
  name: 'sessionId'
};

app.use(session(sessionConfig));

const twilioAccountSid = process.env.TWILIO_ACCOUNT_SID;
const twilioAuthToken = process.env.TWILIO_AUTH_TOKEN;
const twilioPhoneNumber = process.env.TWILIO_PHONE_NUMBER;

let twilioClient = null;
if (twilioAccountSid && twilioAuthToken) {
  const twilio = require('twilio');
  twilioClient = twilio(twilioAccountSid, twilioAuthToken);
}

const otpStore = new Map();

const OTP_EXPIRY = 5 * 60 * 1000;
const MAX_ATTEMPTS = 3;
const RATE_LIMIT_WINDOW = 15 * 60 * 1000;
const MAX_REQUESTS_PER_WINDOW = 5;

const sendSmsLimiter = rateLimit({
  windowMs: RATE_LIMIT_WINDOW,
  max: MAX_REQUESTS_PER_WINDOW,
  message: { error: 'Too many SMS requests. Please try again later.' },
  standardHeaders: true,
  legacyHeaders: false,
  handler: (req, res) => {
    res.status(429).json({ error: 'Too many SMS requests. Please try again later.' });
  }
});

const verifyOtpLimiter = rateLimit({
  windowMs: RATE_LIMIT_WINDOW,
  max: MAX_REQUESTS_PER_WINDOW * 2,
  message: { error: 'Too many verification attempts. Please try again later.' },
  standardHeaders: true,
  legacyHeaders: false,
  handler: (req, res) => {
    res.status(429).json({ error: 'Too many verification attempts. Please try again later.' });
  }
});

function generateOTP() {
  return crypto.randomInt(100000, 999999).toString();
}

function sanitizePhoneNumber(phone) {
  const cleaned = phone.replace(/\D/g, '');
  
  if (cleaned.length === 10) {
    return '+1' + cleaned;
  } else if (cleaned.length === 11 && cleaned.startsWith('1')) {
    return '+' + cleaned;
  } else if (cleaned.startsWith('+')) {
    return phone.replace(/\D/g, '').replace(/^/, '+');
  }
  
  return cleaned.length >= 10 ? '+' + cleaned : null;
}

function validatePhoneNumber(phone) {
  const phoneRegex = /^\+[1-9]\d{1,14}$/;
  return phoneRegex.test(phone);
}

async function sendSMS(phoneNumber, message) {
  if (!twilioClient) {
    console.log(`[DEV MODE] SMS to ${phoneNumber}: ${message}`);
    return { success: true, dev: true };
  }

  try {
    const result = await twilioClient.messages.create({
      body: message,
      from: twilioPhoneNumber,
      to: phoneNumber
    });
    return { success: true, sid: result.sid };
  } catch (error) {
    console.error('Twilio SMS Error:', error);
    throw new Error('Failed to send SMS');
  }
}

function createOTPSession(userId, phoneNumber, otp) {
  const sessionId = crypto.randomBytes(32).toString('hex');
  const hashedOTP = crypto.createHash('sha256').update(otp).digest('hex');
  
  otpStore.set(sessionId, {
    userId,
    phoneNumber,
    hashedOTP,
    attempts: 0,
    createdAt: Date.now(),
    expiresAt: Date.now() + OTP_EXPIRY
  });

  setTimeout(() => {
    otpStore.delete(sessionId);
  }, OTP_EXPIRY);

  return sessionId;
}

function cleanupExpiredOTPs() {
  const now = Date.now();
  for (const [sessionId, data] of otpStore.entries()) {
    if (data.expiresAt < now) {
      otpStore.delete(sessionId);
    }
  }
}

setInterval(cleanupExpiredOTPs, 60000);

app.post('/api/auth/send-otp', sendSmsLimiter, async (req, res) => {
  try {
    const { userId, phoneNumber } = req.body;

    if (!userId || !phoneNumber) {
      return res.status(400).json({ error: 'User ID and phone number are required' });
    }

    if (typeof userId !== 'string' || userId.length < 1 || userId.length > 100) {
      return res.status(400).json({ error: 'Invalid user ID' });
    }

    const sanitizedPhone = sanitizePhoneNumber(phoneNumber);
    
    if (!sanitizedPhone || !validatePhoneNumber(sanitizedPhone)) {
      return res.status(400).json({ error: 'Invalid phone number format' });
    }

    const otp = generateOTP();
    const message = `Your verification code is: ${otp}. This code will expire in 5 minutes. Do not share this code with anyone.`;

    await sendSMS(sanitizedPhone, message);

    const sessionId = createOTPSession(userId, sanitizedPhone, otp);
    
    req.session.otpSessionId = sessionId;
    req.session.userId = userId;

    res.json({ 
      success: true, 
      message: 'OTP sent successfully',
      expiresIn: OTP_EXPIRY / 1000
    });

  } catch (error) {
    console.error('Send OTP Error:', error);
    res.status(500).json({ error: 'Failed to send OTP. Please try again.' });
  }
});

app.post('/api/auth/verify-otp', verifyOtpLimiter, (req, res) => {
  try {
    const { otp } = req.body;
    const { otpSessionId, userId } = req.session;

    if (!otp || !otpSessionId || !userId) {
      return res.status(400).json({ error: 'Invalid request. Please request a new OTP.' });
    }

    if (!/^\d{6}$/.test(otp)) {
      return res.status(400).json({ error: 'OTP must be a 6-digit number' });
    }

    const otpData = otpStore.get(otpSessionId);

    if (!otpData) {
      return res.status(400).json({ error: 'OTP session not found or expired. Please request a new OTP.' });
    }

    if (Date.now() > otpData.expiresAt) {
      otpStore.delete(otpSessionId);
      delete req.session.otpSessionId;
      return res.status(400).json({ error: 'OTP has expired. Please request a new OTP.' });
    }

    if (otpData.attempts >= MAX_ATTEMPTS) {
      otpStore.delete(otpSessionId);
      delete req.session.otpSessionId;
      return res.status(429).json({ error: 'Maximum verification attempts exceeded. Please request a new OTP.' });
    }

    otpData.attempts++;

    const hashedInputOTP = crypto.createHash('sha256').update(otp).digest('hex');

    const isValid = crypto.timingSafeEqual(
      Buffer.from(hashedInputOTP, 'hex'),
      Buffer.from(otpData.hashedOTP, 'hex')
    );

    if (!isValid) {
      const remainingAttempts = MAX_ATTEMPTS - otpData.attempts;
      return res.status(400).json({ 
        error: 'Invalid OTP',
        remainingAttempts
      });
    }

    otpStore.delete(otpSessionId);
    delete req.session.otpSessionId;

    req.session.authenticated = true;
    req.session.twoFactorVerified = true;
    req.session.verifiedAt = Date.now();

    res.json({ 
      success: true, 
      message: 'OTP verified successfully',
      userId: otpData.userId
    });

  } catch (error) {
    console.error('Verify OTP Error:', error);
    res.status(500).json({ error: 'Verification failed. Please try again.' });
  }
});

app.post('/api/auth/resend-otp', sendSmsLimiter, async (req, res) => {
  try {
    const { otpSessionId, userId } = req.session;

    if (!otpSessionId || !userId) {
      return res.status(400).json({ error: 'No active OTP session. Please start authentication again.' });
    }

    const oldOtpData = otpStore.get(otpSessionId);
    
    if (!oldOtpData) {
      return res.status(400).json({ error: 'OTP session expired. Please start authentication again.' });
    }

    otpStore.delete(otpSessionId);

    const otp = generateOTP();
    const message = `Your verification code is: ${otp}. This code will expire in 5 minutes. Do not share this code with anyone.`;

    await sendSMS(oldOtpData.phoneNumber, message);

    const newSessionId = createOTPSession(userId, oldOtpData.phoneNumber, otp);
    
    req.session.otpSessionId = newSessionId;

    res.json({ 
      success: true, 
      message: 'New OTP sent successfully',
      expiresIn: OTP_EXPIRY / 1000
    });

  } catch (error) {
    console.error('Resend OTP Error:', error);
    res.status(500).json({ error: 'Failed to resend OTP. Please try again.' });
  }
});

app.get('/api/auth/status', (req, res) => {
  const isAuthenticated = req.session.authenticated && req.session.twoFactorVerified;
  
  res.json({
    authenticated: isAuthenticated || false,
    userId: isAuthenticated ? req.session.userId : null
  });
});

app.post('/api/auth/logout', (req, res) => {
  const { otpSessionId } = req.session;
  
  if (otpSessionId) {
    otpStore.delete(otpSessionId);
  }

  req.session.destroy((err) => {
    if (err) {
      return res.status(500).json({ error: 'Logout failed' });
    }
    res.json({ success: true, message: 'Logged out successfully' });
  });
});

function requireAuth(req, res, next) {
  if (!req.session.authenticated || !req.session.twoFactorVerified) {
    return res.status(401).json({ error: 'Authentication required' });
  }
  next();
}

app.get('/api/protected/resource', requireAuth, (req, res) => {
  res.json({ 
    message: 'This is a protected resource',
    userId: req.session.userId
  });
});

app.use((err, req, res, next) => {
  console.error('Error:', err);
  res.status(500).json({ error: 'Internal server error' });
});

const PORT = process.env.PORT || 3000;

app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
  if (!twilioClient) {
    console.log('WARNING: Running in development mode without Twilio. SMS will be logged to console.');
  }
});

module.exports = app;